usageExamples:
import { IconButton } from '@zephrui/ui-react';
import { MaterialIcon } from '@zephrui/icons-material';
<IconButton icon={<MaterialIcon name='search' />} label='Search' />

import { Progress } from '@zephrui/ui-react';
<Progress variant='line-label' value={80} title='Data Storage' showValue description='to unlock unlimited data storage.' actionLabel='Upgrade' />
<Progress variant='circle' value={75} circleSize={64} showValue />

import { ComboBox } from '@zephrui/ui-react';
<ComboBox
  options={[{value:'react',label:'React'},{value:'vue',label:'Vue'}]}
  value={framework}
  onChange={setFramework}
  placeholder='Select framework'
/>

import { AlertDialog } from '@zephrui/ui-react';
<AlertDialog
  open={showConfirm}
  onClose={() => setShowConfirm(false)}
  title='Delete project?'
  description='This cannot be undone.'
  confirmLabel='Delete'
  confirmTone='danger'
  onConfirm={handleDelete}
/>
